import javax.naming.*;
import javax.naming.directory.*;
import java.util.HashMap;
import java.util.Map;

public class LDAPUserSearch {

    private static final String LDAP_URL = "ldap://ldap.example.com:389/";
    private static final String LDAP_USER = "ldapuser";
    private static final String LDAP_PASSWORD = "ldappassword";

    public Map<String, String> findUserByUsername(String username) throws Exception {
        DirContext ctx = new InitialDirContext(new Hashtable<String, String>() {{
            put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            put(Context.PROVIDER_URL, LDAP_URL);
            put(Context.SECURITY_PRINCIPAL, LDAP_USER);
            put(Context.SECURITY_CREDENTIALS, LDAP_PASSWORD.toCharArray());
        }});

        SearchControls controls = new SearchControls();
        controls.setSearchScope(SearchControls.SUBTREE_SCOPE);
        controls.addAttribute("mail");
        controls.addAttribute("displayName");
        controls.addAttribute("department");

        String filter = "(& (objectClass=person) (uid=" + username + "))";
        NamingEnumeration<SearchResult> results = ctx.search("", filter, controls);

        if (!results.hasMoreElements()) {
            return null;
        }

        SearchResult result = results.next();
        Attributes attrs = result.getAttributes();

        Map<String, String> user = new HashMap<>();
        user.put("email", (String) attrs.get("mail").get(0));
        user.put("fullName", (String) attrs.get("displayName").get(0));
        user.put("department", (String) attrs.get("department").get(0));

        return user;
    }
}